CREATE TABLE `compras` (
  `id_compra` int NOT NULL AUTO_INCREMENT,
  `id_adulto` int DEFAULT NULL,
  `fecha_compra` datetime DEFAULT CURRENT_TIMESTAMP,
  `total` decimal(10,2) DEFAULT NULL,
  `estado` enum('Completada','Pendiente','Cancelada') DEFAULT 'Pendiente',
  `metodo_pago` enum('Tarjeta de Credito','Tarjeta de Debito','PayPal') NOT NULL,
  `id_pedido` int DEFAULT NULL,
  PRIMARY KEY (`id_compra`),
  KEY `id_adulto` (`id_adulto`),
  KEY `idx_compras_adulto` (`id_adulto`),
  KEY `idx_compras_jugador_fecha` (`id_adulto`,`fecha_compra`),
  KEY `idx_compras_adulto_fecha` (`id_adulto`,`fecha_compra`),
  KEY `idx_compras_pedido` (`id_pedido`),
  CONSTRAINT `compras_ibfk_1` FOREIGN KEY (`id_adulto`) REFERENCES `adultos` (`id_adulto`),
  CONSTRAINT `compras_ibfk_2` FOREIGN KEY (`id_pedido`) REFERENCES `pedido` (`id_pedido`),
  CONSTRAINT `chk_compra_total` CHECK ((`total` >= 0)),
  CONSTRAINT `chk_estado_compra` CHECK ((`estado` in (_utf8mb4'Completada',_utf8mb4'Pendiente',_utf8mb4'Cancelada'))),
  CONSTRAINT `chk_total` CHECK ((`total` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
