INSERT INTO `productos` VALUES (1,'EcoAventura','Videojuego Educativo: Aprende jugando.',130.00,'Juego'),(2,'Sombrero charro','Un clásico mexicano que le da estilo y valentía a tu aventura.',20.00,'Skins'),(3,'Sombrero de bruja','Misterioso y mágico, perfecto para explorar bosques encantados.',18.00,'Skins'),(4,'Corona de hojas','Hecha con hojas verdes, representa tu conexión con la naturaleza.',15.00,'Skins'),(5,'Casco de reciclaje','Ideal para héroes ecológicos que cuidan el planeta.',22.00,'Skins'),(6,'Gorra solar','Energizada por el sol, simboliza energía limpia y renovable.',17.00,'Skins'),(7,'Sombrero de explorador','Perfecto para descubrir nuevos ecosistemas y secretos.',19.00,'Skins'),(8,'Casco de astronauta verde','Para aventurarte más allá del planeta… ¡pero cuidándolo!',25.00,'Skins'),(9,'Corona de flores','Alegre y colorida, refleja amor por la biodiversidad.',16.00,'Skins'),(10,'Sombrero de hongo','Inspirado en el bosque, pequeño pero lleno de vida.',14.00,'Skins'),(11,'Gorra de guardabosques','Para proteger la flora y fauna en cada misión.',18.00,'Skins'),(12,'Casco de bicicleta ecológica','Representa movilidad sostenible y diversión.',17.00,'Skins'),(13,'Sombrero de nube','Ligero y suave, como cuidar el aire que respiramos.',13.00,'Skins'),(14,'Casco de buzo','Para explorar y proteger los océanos y su vida marina.',21.00,'Skins'),(15,'Corona de frutas','Fresca y natural, celebra la riqueza de la tierra.',16.00,'Skins'),(16,'Sombrero de volcán','Poderoso y único, inspirado en la fuerza de la naturaleza.',23.00,'Skins');
